{"code": "import json

articles_data = locals()['var_functions.query_db:16']

# Simple classification to identify sports articles
sports_articles = []

for article in articles_data:
    title_lower = article['title'].lower()
    desc_lower = article['description'].lower()

    # Check for sports content
    sports_indicators = ['football','basketball','baseball','soccer','tennis','golf','olympics','athlete','athletes','coach','game','match','player','team','season','league','championship','tournament','race','hockey','cricket','rugby','boxing','sport','sports','nba','nfl','mlb','nhl','ncaa']

    is_sports = False
    combined_text = title_lower + ' ' + desc_lower

    for indicator in sports_indicators:
        if indicator in combined_text:
            is_sports = True
            break

    if is_sports:
        sports_articles.append({
            'article_id': article['article_id'],
            'title': article['title'],
            'description': article['description'],
            'description_length': len(article['description'])
        })

# Find longest sports article if any exist
longest_article = None
if sports_articles:
    longest_article = max(sports_articles, key=lambda x: x['description_length'])

result = {
    'sports_count': len(sports_articles),
    'longest_article': longest_article
}

print('__RESULT__:')
print(json.dumps(result))"}
